    """Count users reachable via follow edges (excluding start) not directly blocked by start."""
    adj = {}
    for pair in spec["follows"]:
        if pair[0] not in adj:
            adj[pair[0]] = []
        adj[pair[0]].append(pair[1])
    seen = set()
    stack = [spec["start"]]
