        seen.add(n)
        if n in adj:
            stack.extend(adj[n])
    blocked = []
    for pair in spec["blocks"]:
        if pair[0] == spec["start"]:
            blocked.append(pair[1])
    count = 0
    for n in seen:
        if n != spec["start"] and n not in blocked:
            count += 1
    return count

